// stringify: convertir a texto para enviar o guardar
const producto = {
  id: 42,
  nombre: 'Laptop',
  precio: 2500000,
  disponible: true,
  etiquetas: ['electrónica', 'oferta']
};

const json = JSON.stringify(producto);
console.log(json);
// {"id":42,"nombre":"Laptop","precio":2500000,"disponible":true,"etiquetas":["electrónica","oferta"]}

console.log(typeof json); // 'string'

// parse: recibir texto y convertirlo a objeto usable
const respuestaServidor = '{"usuarios":[{"id":1,"nombre":"Ana"},{"id":2,"nombre":"Luis"}]}';

const datos = JSON.parse(respuestaServidor);
console.log(datos.usuarios.length);    // 2
console.log(datos.usuarios[0].nombre); // 'Ana'

// Ahora puedes usar todos los métodos de array
const nombres = datos.usuarios.map(u => u.nombre);
console.log(nombres); // ['Ana', 'Luis']

// Errores comunes con JSON

// ❌ Claves sin comillas
// JSON.parse("{ nombre: 'Ana' }"); // SyntaxError

// ❌ Comillas simples
// JSON.parse("{ 'nombre': 'Ana' }"); // SyntaxError

// ✅ Siempre comillas dobles
JSON.parse('{ "nombre": "Ana" }'); // OK

// Valores que stringify ignora
const obj = { nombre: 'Ana', fn: () => 42, x: undefined };
console.log(JSON.stringify(obj)); // '{"nombre":"Ana"}' — fn y x desaparecen

